 ARRAY['recruiting', 'hr-tech'],
 'paid', false, 0.00,
 4.3, 287, false, false, false,
 ARRAY['TalentGPT connects internal mobility with external recruiting', 'Skills taxonomy enables workforce planning by skill gap', 'Covers full talent lifecycle from acquisition to development', 'Purpose-built for large enterprise complexity'],
 ARRAY['Enterprise-only pricing and implementation timeline', 'Significant configuration required to match skills taxonomy to your organization', 'ROI requires sustained program management investment'],
 ARRAY['Strategic workforce planning based on skills gap analysis', 'Connecting internal mobility to external recruiting to reduce cost-per-hire', 'Building a talent intelligence layer across a large enterprise'],
