 'paid', false, 0.00,
 4.4, 531, false, true, false,
 ARRAY['Skills inference from career trajectories - not just listed skills', 'Identifies at-risk employees and surfaces internal opportunities', 'Enables skills-based hiring by removing reliance on credentials', 'Deep learning trained on hundreds of millions of career paths'],
 ARRAY['Enterprise platform - complex implementation and significant investment', 'Effectiveness depends on data quality and integration depth', 'Benefits compound over time - slower ROI for recent adopters'],
 ARRAY['Implementing skills-based hiring to reduce credential bias', 'Predicting employee flight risk and enabling proactive retention', 'Building internal mobility programs at large enterprises'],
