 'paid', false, 0.00,
 4.6, 284, false, true, false,
 ARRAY['AI-generated interview notes aligned to scorecard criteria', 'Interviewers stay present in conversation instead of typing notes', 'Direct ATS integration - notes push to Greenhouse, Lever, Ashby', 'Reduces post-interview admin from 20 minutes to under 2 minutes'],
 ARRAY['Candidate consent and recording disclosure required (varies by jurisdiction)', 'Value depends on structured hiring process being in place', 'AI note quality varies with audio clarity and interview format'],
 ARRAY['Improving interview quality by letting interviewers focus on candidates', 'Reducing post-interview admin for high-volume recruiting teams', 'Standardizing interview evidence capture for structured hiring programs'],
